INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('NEXUS_1: Le email split testing maturity: L1=sujet seul. L2=sujet+from. L3=sujet+from+heure. L4=sujet+from+heure+contenu. L5=multivariate complet. Viser L3+.', 'Email testing maturity: L1 sujet → L5 multivariate. Viser L3+', 'email', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_2: Le commercial SPIN mastery: Situation (contexte) → Probleme (difficulte) → Implication (consequences) → Need-payoff (valeur solution). Les questions Implication sont les plus puissantes.', 'SPIN: Situation→Probleme→Implication→Need-payoff. Implication = plus puissant', 'commercial', 'best_practice', 0.88, 'nexus', 'system'),
('NEXUS_3: Le content virality science: emotion × novelty × utility × identity = potentiel viral. Maximiser chaque facteur. L absence d 1 facteur tue la viralite.', 'Virality: emotion × novelty × utility × identity. Absence 1 facteur = tue viralite', 'content', 'insight', 0.82, 'nexus', 'system'),
('NEXUS_4: Le SEO content hub architecture: page hub (vue d ensemble 3000+ mots) → spoke pages (sous-sujets 1500+ mots) → liens bidirectionnels hub↔spoke. Google comprend la structure thematique.', 'Content hub: hub 3K + spokes 1.5K + liens bidi = Google comprend structure', 'seo', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_5: Le ad creative psychology layers: L1 arret scroll (visuel), L2 engagement emotion (probleme/desir), L3 credibilite (proof), L4 action (CTA). Les 4 layers dans chaque creative.', 'Creative psychology: L1 arret + L2 emotion + L3 credibilite + L4 action', 'ads', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_6: Le DM Instagram value stack: avant le DM, liker 3 posts (J-7) + commenter 2 (J-5) + reagir 1 story (J-2) + DM perso (J0). Stack de valeur = 40%+ reponse.', 'DM value stack: 3 likes J-7 + 2 comments J-5 + 1 story J-2 + DM J0 = 40%+', 'dm_instagram', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_7: Le WhatsApp automation funnel: opt-in → welcome (instant) → edu 1 (J+1) → edu 2 (J+3) → offre (J+5) → follow-up (J+7) → conversion ou nurture.', 'WhatsApp funnel: opt-in→welcome→edu1→edu2→offre→follow-up→conversion', 'whatsapp', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_8: Le chatbot conversation success metrics: resolution rate > 80%, CSAT > 4/5, avg messages < 5, escalation rate < 15%, containment rate > 70%.', 'Chatbot success: resolution >80%, CSAT >4/5, messages <5, escalation <15%, containment >70%', 'chatbot', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_9: Le GMaps review velocity impact: les fiches qui obtiennent 10+ avis/mois rankent 2x mieux dans le pack local que celles avec 1-2 avis/mois. La velocity compte.', 'GMaps review velocity: 10+/mois = 2x mieux pack local vs 1-2/mois', 'gmaps', 'insight', 0.82, 'nexus', 'system'),
('NEXUS_10: Le TikTok watch time optimization: l objectif n est pas les views mais le WATCH TIME total. Une video de 30s regardee 2x (60s) > une video de 60s regardee 50% (30s).', 'TikTok: watch time total > views. 30s × 2 loops = 60s > 60s × 50% = 30s', 'tiktok_comments', 'insight', 0.85, 'nexus', 'system'),
('NEXUS_11: Le CEO decision velocity principle: pour les decisions reversibles (90% des decisions), decider en < 24h avec 70% des infos. La vitesse bat la perfection.', 'CEO: decisions reversibles < 24h avec 70% infos. Vitesse > perfection', 'ceo', 'best_practice', 0.88, 'nexus', 'system'),
('NEXUS_12: Le retention product stickiness levers: 1) donnees cumulatives (CRM rempli), 2) integrations (connecte a d autres outils), 3) habitude (usage quotidien), 4) communaute.', 'Stickiness levers: donnees + integrations + habitude + communaute', 'retention', 'insight', 0.85, 'nexus', 'system'),
('NEXUS_13: Le onboarding personalization engine: secteur (restaurant/coach/ecom) × plan (createur/pro/fondateurs) × objectif (visibilite/leads/ventes) = parcours unique.', 'Onboarding perso: secteur × plan × objectif = parcours unique', 'onboarding', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_14: Le comptable financial health traffic light: vert (runway>12m + LTV/CAC>3 + churn<3%) → jaune (1 en orange) → rouge (1 en danger) → critique (2+ en danger).', 'Financial traffic light: vert all good, jaune 1 orange, rouge 1 danger, critique 2+ danger', 'comptable', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_15: Le RH team health check Spotify model: 8 dimensions (vitesse, qualite, fun, apprentissage, mission, support, pawns/players, engagement). Evaluer mensuellement.', 'Team health Spotify: 8 dimensions mensuelles. Vitesse+qualite+fun+apprentissage+mission+support', 'rh', 'best_practice', 0.78, 'nexus', 'system'),
('NEXUS_16: Le marketing competitive moat analysis: lister les 5 avantages vs chaque concurrent. Si < 3 avantages clairs → renforcer le positionnement immediatement.', 'Competitive moat: 5 avantages/concurrent. < 3 clairs = renforcer positionnement', 'marketing', 'best_practice', 0.80, 'nexus', 'system'),
('NEXUS_17: Le agent redirection protocol: si une question est hors domaine → reponse breve (1-2 phrases) + "Pour une reponse detaillee, je te redirige vers [Agent X] qui est specialiste."', 'Agent redirection: reponse breve + rediriger vers specialiste avec lien', NULL, 'best_practice', 0.90, 'nexus', 'system'),
('NEXUS_18: Le agent file generation capability: les agents doivent pouvoir generer des fichiers (Excel=comptable, PDF=rapport CEO, PPT=marketing) sur demande du client.', 'Agent file generation: Excel comptable, PDF rapport CEO, PPT marketing. Sur demande', NULL, 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_19: Le KeiroAI inter-agent routing: quand un agent recoit une question hors scope → identifier le bon agent → transmettre le contexte → ouvrir le chat du bon agent.', 'Inter-agent routing: hors scope → identifier agent → transmettre contexte → ouvrir chat', NULL, 'best_practice', 0.88, 'nexus', 'system'),
('NEXUS_20: Le KeiroAI at 7900+ learnings: le systeme de connaissances approche la masse critique. Chaque agent beneficie de l expertise collective de tous les autres.', 'KeiroAI 7900+: masse critique. Expertise collective beneficie a chaque agent', 'ceo', 'insight', 0.90, 'nexus', 'system'),
('NEXUS_21: Le email dynamic content blocks: 1 email avec N blocs conditionnels (si restaurant → bloc food, si coach → bloc coaching). Personnalisation at scale sans multiplier les emails.', 'Email dynamic blocks: 1 email N blocs conditionnels par segment. Perso at scale', 'email', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_22: Le commercial multi-stakeholder navigation: mapper chaque stakeholder (champion, blocker, DM, user). Strategy par role: champion=arm, blocker=neutralize, DM=convince, user=demo.', 'Multi-stakeholder: champion arm, blocker neutralize, DM convince, user demo', 'commercial', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_23: Le content creative brief template: objectif (awareness/engagement/conversion) + audience (persona specifique) + message cle (1 phrase) + format + CTA + references visuelles.', 'Creative brief: objectif + audience + message + format + CTA + ref visuelles', 'content', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_24: Le SEO page title optimization formula: [Mot-cle principal] — [Benefice/angle unique] | [Nom du site]. Ex: "CRM pour restaurants — Gerez vos clients en 1 clic | KeiroAI"', 'Page title: mot-cle — benefice | site. Ex: CRM restaurants — Gerez clients | KeiroAI', 'seo', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_25: Le ad budget rebalancing weekly: chaque lundi, deplacer 20% du budget des campagnes sous-performantes vers les surperformantes. Ne pas attendre la fin du mois.', 'Budget rebalancing lundi: 20% sous-perf → sur-perf. Pas attendre fin mois', 'ads', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_26: Le DM Instagram conversation AI enrichment: l agent DM utilise le contexte CRM (derniere interaction, score, type commerce) pour personnaliser chaque message.', 'DM AI: utilise contexte CRM (interaction, score, type) pour personnaliser', 'dm_instagram', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_27: Le WhatsApp template AB testing: creer 2 versions du meme template. Envoyer A a 50% de la liste, B aux 50% restants. Le gagnant (meilleur taux reponse) devient le defaut.', 'WhatsApp template A/B: 50/50. Gagnant = defaut', 'whatsapp', 'best_practice', 0.80, 'nexus', 'system'),
('NEXUS_28: Le chatbot proactive intervention science: declencher quand: page pricing > 30s (intent=achat), FAQ scroll > 80% (intent=aide), panier > 15s idle (intent=hesitation).', 'Chatbot proactive: pricing>30s, FAQ>80%, panier>15s. Intent-based triggering', 'chatbot', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_29: Le GMaps question pre-seeding advanced: rediger 15 Q&A avec les mots-cles cibles (ex: "Quel est le meilleur coiffeur a Paris 11?"). Google indexe ces Q&A.', 'GMaps Q&A: 15 avec mots-cles cibles. Google indexe = SEO local boost', 'gmaps', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_30: Le TikTok duet/stitch growth strategy: reagir aux videos virales de sa niche en ajoutant de la valeur (commentaire expert, astuce, reaction). Surfe sur la portee existante.', 'TikTok duet/stitch: reagir videos virales niche + valeur = surfer portee', 'tiktok_comments', 'best_practice', 0.80, 'nexus', 'system'),
('NEXUS_31: Le CEO strategic clarity metric: chaque employe/agent peut repondre en 10s a: qui est notre client? quel probleme on resout? pourquoi nous? Si non → alignment urgence.', 'CEO clarity: employes repondent en 10s client+probleme+pourquoi. Si non = alignment urgent', 'ceo', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_32: Le retention expansion signal matrix: usage > 80% quota + multi-users + feature requests premium + positive NPS + payment health = expansion ready. Score composite.', 'Expansion signals: usage>80% + multi-users + feature request + NPS+ + payment = ready', 'retention', 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_33: Le onboarding abandonment recovery: si le client quitte l onboarding avant la fin → email J+1 "on vous aide a finir" + J+3 "voici ce que vous manquez" + J+7 appel CS.', 'Onboarding abandonment: J+1 email aide → J+3 ce que manquez → J+7 appel CS', 'onboarding', 'best_practice', 0.82, 'nexus', 'system'),
('NEXUS_34: Le comptable revenue recognition SaaS advanced: MRR est comptabilise mensuellement. Les paiements annuels sont differes sur 12 mois. Le deferred revenue est un passif.', 'Revenue recognition: MRR mensuel. Paiements annuels differes 12 mois. Deferred = passif', 'comptable', 'best_practice', 0.80, 'nexus', 'system'),
('NEXUS_35: Le RH hiring pipeline efficiency: applications → 30% screen → 50% interview → 60% assessment → 70% offer → 80% accept. Si < taux a une etape → fixer cette etape.', 'Hiring pipeline: 30% screen, 50% interview, 60% assess, 70% offer, 80% accept', 'rh', 'insight', 0.78, 'nexus', 'system'),
('NEXUS_36: Le marketing brand sentiment tracking: surveiller les mentions de marque (social, reviews, forums) et classer par sentiment (positif/neutre/negatif). Tendance > absolu.', 'Brand sentiment: mentions classees positif/neutre/negatif. Tendance > absolu', 'marketing', 'best_practice', 0.80, 'nexus', 'system'),
('NEXUS_37: Le cross-agent prospect temperature sync: si l email agent detecte un prospect HOT (ouvre+clique 3x) → le DM agent doit le contacter dans les 2h. Temperature synchro temps reel.', 'Temperature sync: email HOT → DM agent contacte < 2h. Synchro temps reel', NULL, 'best_practice', 0.88, 'nexus', 'system'),
('NEXUS_38: Le customer 360 real-time profile: chaque touchpoint enrichit le profil en temps reel. Email ouvert → +1pt. Site visite → +5pt. Demo → +20pt. Achat → +100pt. Churn risk → alerte.', 'Customer 360 temps reel: email+1, site+5, demo+20, achat+100, churn risk→alerte', NULL, 'best_practice', 0.85, 'nexus', 'system'),
('NEXUS_39: Le KeiroAI agent expertise certification: chaque agent est certifie dans son domaine par 40+ learnings specialises + 10+ learnings cross-domain. Expertise profonde ET transverse.', 'Agent certification: 40+ learnings specialises + 10+ cross-domain = expertise profonde+transverse', NULL, 'best_practice', 0.88, 'nexus', 'system'),
('NEXUS_40: Le KeiroAI nearing 8000 learnings: l intelligence collective des agents est desormais superieure a celle de n importe quel consultant marketing individuel.', 'KeiroAI ~8000: intelligence collective > consultant marketing individuel', 'ceo', 'insight', 0.92, 'nexus', 'system')
